(function($){
  if(!$ || !$.fn){return;}
  if($.fn.DataTable){return;}

  function SimpleDataTable($table, options){
    this.$table = $table;
    this.options = $.extend(true, { order: [[0, "asc"]], ajax: null, columnDefs: [], paging: true, pageLength: 10, lengthMenu: [10, 25, 50, 100], lengthChange: true, info: true }, options || {});
    this.state = { draw: 1, start: 0, length: this.options.pageLength || 10, order: this.options.order, columns: [] };
    this.lastResponse = null;
    this.initColumns();
    this.load();
  }

  SimpleDataTable.prototype.initColumns = function(){
    var count = this.$table.find("thead").first().find("th").length || 0;
    this.state.columns = [];
    for(var i=0;i<count;i++){
      this.state.columns.push({ search: { value: "" } });
    }
  };

  SimpleDataTable.prototype.buildRequest = function(){
    var order = this.state.order || [[0, "asc"]];
    return {
      draw: this.state.draw,
      start: this.state.start,
      length: this.state.length,
      order: [{ column: order[0][0], dir: order[0][1] }],
      columns: this.state.columns
    };
  };

  SimpleDataTable.prototype.applyColumnDefs = function(cellData, rowData, rowIndex, colIndex){
    var defs = this.options.columnDefs || [];
    for(var i=0;i<defs.length;i++){
      var def = defs[i] || {};
      var targets = def.targets;
      var hit = false;
      if(Array.isArray(targets)){
        hit = targets.indexOf(colIndex) >= 0;
      }else{
        hit = (targets === colIndex);
      }
      if(hit && typeof def.render === "function"){
        var renderData = (def.data === null) ? rowData : cellData;
        return def.render(renderData, "display", rowData, { row: rowIndex, col: colIndex });
      }
    }
    return cellData;
  };

  SimpleDataTable.prototype.render = function(rows){
    var $tbody = this.$table.find("tbody");
    $tbody.empty();
    for(var r=0;r<rows.length;r++){
      var rowData = rows[r];
      var $tr = $("<tr/>");
      for(var c=0;c<rowData.length;c++){
        var cellData = rowData[c];
        var cellHtml = this.applyColumnDefs(cellData, rowData, r, c);
        var $td = $("<td/>");
        $td.html(cellHtml == null ? "" : cellHtml);
        $tr.append($td);
      }
      $tbody.append($tr);
    }
  };

  SimpleDataTable.prototype.ensureControls = function(){
    if(this.$controls){return;}
    this.$controls = $("<div class=\"dataTables_controls\" style=\"display:flex;justify-content:space-between;align-items:center;margin-top:0.5rem;gap:0.75rem;flex-wrap:wrap;\"></div>");
    this.$length = $("<div class=\"dataTables_length\"></div>");
    this.$info = $("<div class=\"dataTables_info\"></div>");
    this.$paginate = $("<div class=\"dataTables_paginate\" style=\"display:flex;align-items:center;gap:0.5rem;\"></div>");
    this.$controls.append(this.$length, this.$info, this.$paginate);
    this.$table.after(this.$controls);
  };

  SimpleDataTable.prototype.renderLengthMenu = function(){
    if(!this.options.lengthChange){
      this.$length.empty();
      return;
    }
    var self = this;
    var $select = $("<select class=\"form-select form-select-sm\" style=\"width:auto;\"></select>");
    var menu = this.options.lengthMenu || [10, 25, 50, 100];
    for(var i=0;i<menu.length;i++){
      var val = menu[i];
      var $opt = $("<option></option>").attr("value", val).text(val);
      if(parseInt(val, 10) === parseInt(this.state.length, 10)){
        $opt.attr("selected", "selected");
      }
      $select.append($opt);
    }
    this.$length.empty().append("Show ").append($select).append(" entries");
    $select.off("change").on("change", function(){
      var v = parseInt($(this).val(), 10);
      self.state.length = isNaN(v) ? self.state.length : v;
      self.state.start = 0;
      self.load();
    });
  };

  SimpleDataTable.prototype.renderInfo = function(totalFiltered){
    if(!this.options.info){
      this.$info.empty();
      return;
    }
    var start = this.state.start + 1;
    var end = Math.min(this.state.start + this.state.length, totalFiltered);
    if(totalFiltered === 0){
      this.$info.text("Showing 0 to 0 of 0 entries");
    }else{
      this.$info.text("Showing " + start + " to " + end + " of " + totalFiltered + " entries");
    }
  };

  SimpleDataTable.prototype.renderPager = function(totalFiltered){
    if(!this.options.paging){
      this.$paginate.empty();
      return;
    }
    var self = this;
    var totalPages = Math.ceil(totalFiltered / this.state.length) || 1;
    var currentPage = Math.floor(this.state.start / this.state.length) + 1;
    this.$paginate.empty();

    var $prev = $("<button type=\"button\" class=\"btn btn-sm btn-light\">Prev</button>");
    $prev.prop("disabled", currentPage <= 1);
    $prev.on("click", function(){
      if(currentPage > 1){
        self.state.start = (currentPage - 2) * self.state.length;
        self.load();
      }
    });

    var $next = $("<button type=\"button\" class=\"btn btn-sm btn-light\">Next</button>");
    $next.prop("disabled", currentPage >= totalPages);
    $next.on("click", function(){
      if(currentPage < totalPages){
        self.state.start = currentPage * self.state.length;
        self.load();
      }
    });

    var $label = $("<span style=\"min-width:90px;text-align:center;\"></span>").text("Page " + currentPage + " of " + totalPages);

    this.$paginate.append($prev, $label, $next);
  };

  SimpleDataTable.prototype.load = function(){
    var self = this;
    var ajax = this.options.ajax || {};
    if(!ajax.url){return;}

    var requestData = this.buildRequest();
    if(ajax.data){
      if(typeof ajax.data === "function"){
        requestData = ajax.data(requestData) || requestData;
      }else{
        for(var k in ajax.data){
          if(Object.prototype.hasOwnProperty.call(ajax.data, k)){
            requestData[k] = ajax.data[k];
          }
        }
      }
    }

    $.ajax({
      url: ajax.url,
      type: ajax.type || "GET",
      data: requestData,
      dataType: "json"
    }).done(function(resp){
      if(resp && Array.isArray(resp.data)){
        self.lastResponse = resp;
        self.render(resp.data);
        self.ensureControls();
        var totalFiltered = parseInt(resp.recordsFiltered, 10);
        if(isNaN(totalFiltered)){
          totalFiltered = parseInt(resp.recordsTotal, 10);
        }
        if(isNaN(totalFiltered)){
          totalFiltered = resp.data.length;
        }
        self.renderLengthMenu();
        self.renderInfo(totalFiltered);
        self.renderPager(totalFiltered);
      }
    }).fail(function(){
      if(typeof ajax.error === "function"){ajax.error();}
    });

    this.state.draw += 1;
  };

  SimpleDataTable.prototype.columns = function(index){
    var self = this;
    return {
      search: function(value){
        if(self.state.columns[index]){
          self.state.columns[index].search.value = value;
        }
        return self;
      }
    };
  };

  SimpleDataTable.prototype.draw = function(){
    this.state.start = 0;
    this.load();
  };

  $.fn.DataTable = function(options){
    if(!this.length){return null;}
    return new SimpleDataTable(this, options);
  };
})(window.jQuery);
